#include <stdio.h>
#include <math.h>
int main() {
    int N, Q;
    scanf("%d", &N);
    int x[N], y[N];
    for (int i = 0; i < N; i++) {
        scanf("%d %d", &x[i], &y[i]);
    }
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        int f, t;
        scanf("%d %d", &f, &t);
        double maxDist = 0;
        for (int j = f - 1; j < t; j++) {
            for (int k = j + 1; k < t; k++) {
                double dist = pow(x[j] - x[k], 2) + pow(y[j] - y[k], 2);
                if (dist > maxDist) {
                    maxDist = dist;
                }
            }
        }
        printf("%f\n", maxDist);
    }
    return 0;
}

