import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int[] x = new int[N];
        int[] y = new int[N];
        for (int i = 0; i < N; i++) {
            x[i] = sc.nextInt();
            y[i] = sc.nextInt();
        }
        int Q = sc.nextInt();
        for (int i = 0; i < Q; i++) {
            int f = sc.nextInt();
            int t = sc.nextInt();
            double maxDist = 0;
            for (int j = f - 1; j < t; j++) {
                for (int k = j + 1; k < t; k++) {
                    double dist = Math.pow(x[j] - x[k], 2) + Math.pow(y[j] - y[k], 2);
                    if (dist > maxDist) {
                        maxDist = dist;
                    }
                }
            }
            System.out.println(maxDist);
        }
    }
}

